var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"으아악! 대체 어떤 변태가 이따위로 최적화를 해 놓은 거야!","JPN":"うああ！　一体どこの変態がこんな風に最適化しておいたんだ！","ENG":"Gaaah! Just what kind of psycho optimized the system like this!","TWN":"可惡！是哪個變態進行的優化啦！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"굴하지 마라, 앨버트! 월급쟁이들의 스파게티 코드에 굴해서는 안 된다!","JPN":"屈するな、アルバート！　サラリーマンどものスパゲティコードに屈してはいけない！","ENG":"Don’t cave in, Albert! You must not cave in to the spaghetti code made by capitalist sheep!","TWN":"不能認輸，亞伯特！我們不能輸給領固定薪的義大利麵式程式碼！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"둘 다 좀 닥쳐! 함선에 엔진 하나 연결하는 것 갖고 왜 이리 시끄러워!","JPN":"二人とも黙って！　艦船にエンジン繋げるくらいでなに騒いでんのよ！","ENG":"Both of you, shut up! Are you connecting the engine to the ship with your mouths?!","TWN":"你們兩個都給我安靜點！不過就是將一個引擎連接到艦船而已，有什麼好哇哇叫的！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"저 여자애는 왜 저렇게 성질머리가 더럽나 몰라.","JPN":"あの女の子はなんであんなに性格悪いのかな。","ENG":"I don’t know why that girl has such a bad temper.","TWN":"那女的脾氣怎麼這麼差？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"친구, 저런 사람을 <color=#ffd34c>탄산 없는 사이버캣</color>이라고 부른다는 거 알고 있어?","JPN":"友よ、ああいうのを<color=#ffd34c>炭酸の抜けたサイバーキャット</color>って呼ぶの知ってるか？","ENG":"Yo, did you know that people like that are called <color=#ffd34c>fizzled-out Cyber Cat</color>?","TWN":"朋友，你知道嗎？這種人我們通常稱為<color=#ffd34c>沒料的賽博貓</color>。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"오우, 무슨 뜻이야?","JPN":"おお、どういう意味？","ENG":"Oh? What does that mean?","TWN":"哇喔，這什麼意思？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"폼도 떨어졌는데 성질머리는 더러운 해커를 가리키는 말이야.","JPN":"腕も落ちてんのに、性根が腐っているハッカーのことをそういうんだ。","ENG":"A hacker with no skill and a bad temper.","TWN":"就是指那些虛有其表，然後性格很差的駭客。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HACKER_NPC_NULL_BOTH","text":{"KOREA":"와하하하하!!","JPN":"わはははは！！","ENG":"Ahahahahaha!!","TWN":"哈哈哈哈哈哈哈！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……두 놈 다 미사일에 매달아서 날려 버리고 싶네, 진짜.","JPN":"……二人ともミサイルに縛ってぶっ飛ばしたいわ、マジで。","ENG":"...I really want to tie those two on a missile and launch it.","TWN":"……你們是想被掛在導彈上射出去是吧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래도 어떻게든 탑재는 마무리됐고, 기동 시퀀스만 만져 주면 되려나……","JPN":"でもなんとか搭載できたし、起動シーケンスさえいじればいいか……","ENG":"Anyway, we’ve finished mounting the engine and just need to deal with the start up sequence...","TWN":"總之已經搭載完畢，接下來就是改一下啟動函數……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"에휴, 국방부에 멀쩡한 프로그래머가 한 명만 더 있었어도 저것들은 안 불렀을 텐데.","JPN":"はあ、国防省にまともなプログラマーがもう一人いればあいつらは呼ばなくて済んだのに。","ENG":"Ugh, if only the Department of Defense had one more normal programmer, we wouldn’t have had to use those idiots.","TWN":"哀～要是國防部再多一個堪用的工程師，也不至於找那種傢伙來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"응? 뭐야? 침식파가…….","JPN":"うん？　なに？　侵食波が……","ENG":"Huh? What’s this? The Corruption Ray...","TWN":"嗯？怎麼會？侵蝕波……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":" 5종?!","JPN":" 第5種！？","ENG":" Category 5?!","TWN":"5類？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실비아, 비상 사태다! 외부 카메라 확인해!","JPN":"シルビア、非常状態だ！　外部カメラを確認しろ！","ENG":"Sylvia, it’s an emergency! Check the external cameras!","TWN":"希爾維亞，緊急狀況！立刻確認外部鏡頭！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 저건…? 설마 저게 감찰부대 사람들이라고?","JPN":"なんだ、あれ……？　まさかあれが監察部隊の隊員？","ENG":"What on earth is that...? Don’t tell me... Are those the Inspection Corps soldiers?","TWN":"這是…？該不會是監察組的人？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 슬라임도 아니고 왜 한 덩어리가 된 거야?!","JPN":"いや、スライムでもあるまいし、なんでひとかたまりになってるわけ！？","ENG":"Why are they jumbled together in a single mass?! They’re not even melted together into slime!","TWN":"不對，怎麼不是黏液而是一整團？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};